#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>
#include <cstdlib>
#include <cuda_runtime.h>

#define N 2048
#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N - 1) {
        f[IDX(i, j)] = sinf(j * 2 * M_PI / (N - 1));
      } else if (j == 0 || j == N - 1) {
        f[IDX(i, j)] = sinf(i * 2 * M_PI / (N - 1));
      } else {
        f[IDX(i, j)] = 0.0f;
      }
    }
  }
}

__global__ void jacobi_kernel(const float* __restrict__ f_old,
                              float* __restrict__ f,
                              float* __restrict__ error_sum) {
  __shared__ float sdata[256];

  int tx = threadIdx.x;
  int ty = threadIdx.y;
  int tid = ty * blockDim.x + tx;

  int i = blockIdx.x * blockDim.x + tx + 1;
  int j = blockIdx.y * blockDim.y + ty + 1;

  float local = 0.0f;
  if (i <= N - 2 && j <= N - 2) {
    float t = 0.25f * (f_old[IDX(i - 1, j)] +
                       f_old[IDX(i + 1, j)] +
                       f_old[IDX(i, j - 1)] +
                       f_old[IDX(i, j + 1)]);
    float df = t - f_old[IDX(i, j)];
    f[IDX(i, j)] = t;
    local = df * df;
  }

  sdata[tid] = local;
  __syncthreads();

  for (int stride = 128; stride > 0; stride >>= 1) {
    if (tid < stride) sdata[tid] += sdata[tid + stride];
    __syncthreads();
  }

  if (tid == 0) atomicAdd(error_sum, sdata[0]);
}

__global__ void copy_interior_kernel(const float* __restrict__ f,
                                     float* __restrict__ f_old) {
  int i = blockIdx.x * blockDim.x + threadIdx.x + 1;
  int j = blockIdx.y * blockDim.y + threadIdx.y + 1;
  if (i <= N - 2 && j <= N - 2) {
    f_old[IDX(i, j)] = f[IDX(i, j)];
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = (float*)aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*)aligned_alloc(64, N * N * sizeof(float));

  float error = {std::numeric_limits<float>::max()};
  const float tolerance = 1.e-5f;

  initialize_data(f);
  initialize_data(f_old);

  const int max_iters = 10000;
  int num_iters = 0;

  float *d_f = nullptr, *d_f_old = nullptr, *d_error = nullptr;
  cudaMalloc((void**)&d_f, N * N * sizeof(float));
  cudaMalloc((void**)&d_f_old, N * N * sizeof(float));
  cudaMalloc((void**)&d_error, sizeof(float));

  cudaMemcpy(d_f, f, N * N * sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(d_f_old, f_old, N * N * sizeof(float), cudaMemcpyHostToDevice);

  dim3 block(16, 16);
  dim3 grid((N - 2 + block.x - 1) / block.x, (N - 2 + block.y - 1) / block.y);

  auto start = std::chrono::steady_clock::now();

  while (error > tolerance && num_iters < max_iters) {
    cudaMemset(d_error, 0, sizeof(float));

    jacobi_kernel<<<grid, block>>>(d_f_old, d_f, d_error);
    copy_interior_kernel<<<grid, block>>>(d_f, d_f_old);

    cudaMemcpy(&error, d_error, sizeof(float), cudaMemcpyDeviceToHost);
    error = sqrtf(error / (N * N));

    if (num_iters % 1000 == 0) {
      std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
    }

    ++num_iters;
  }

  cudaDeviceSynchronize();

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (error <= tolerance && num_iters < max_iters) {
    std::cout << "PASS" << std::endl;
  } else {
    std::cout << "FAIL" << std::endl;
    cudaFree(d_f);
    cudaFree(d_f_old);
    cudaFree(d_error);
    free(f);
    free(f_old);
    return -1;
  }

  cudaFree(d_f);
  cudaFree(d_f_old);
  cudaFree(d_error);

  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}

